class Animal:
    def sound(self):
        pass

class Dog(Animal):
    def sound(self):
        print("Woof")

class Cat(Animal):
    def sound(self):
        print("Meow")

try:
    n = int(input())
    animal_types = input()

    animals = []
    for char in animal_types:
        if char == 'D':
            animals.append(Dog())
        elif char == 'C':
            animals.append(Cat())

    for animal in animals:
        animal.sound()
except (ValueError, IndexError):
    pass
